import{_ as a,c as o,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Integração z.ai: Explicação de Limites de Capacidade | Antigravity-Manager","description":"Domine os limites de integração z.ai das Antigravity Tools. Entenda roteamento de solicitação, distribuição dispatch_mode, mapeamento de modelo, estratégia de segurança de Header, e MCP proxy e limitações, evitando julgamentos errados.","frontmatter":{"title":"Integração z.ai: Explicação de Limites de Capacidade | Antigravity-Manager","sidebarTitle":"Verificação rápida de limites z.ai","subtitle":"Integração z.ai: Explicação de Limites de Capacidade","description":"Domine os limites de integração z.ai das Antigravity Tools. Entenda roteamento de solicitação, distribuição dispatch_mode, mapeamento de modelo, estratégia de segurança de Header, e MCP proxy e limitações, evitando julgamentos errados.","tags":["z.ai","MCP","Claude","limites de capacidade"],"prerequisite":["start-getting-started","platforms-mcp"],"order":3},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/appendix/zai-boundaries/index.md"};function d(n,e,c,s,l,m){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="limites-de-capacidade-de-integracao-z-ai-implementado-vs-nao-implementado-explicitamente" tabindex="-1">Limites de Capacidade de Integração z.ai (Implementado vs Não Implementado Explicitamente) <a class="header-anchor" href="#limites-de-capacidade-de-integracao-z-ai-implementado-vs-nao-implementado-explicitamente" aria-label="Permalink to &quot;Limites de Capacidade de Integração z.ai (Implementado vs Não Implementado Explicitamente)&quot;">​</a></h1><p>Este documento só fala dos &quot;limites&quot; do z.ai nas Antigravity Tools, não &quot;como conectar&quot;. Se você descobrir que certo recurso não entrou em vigor, primeiro compare aqui: é porque não foi ativado, não configurado, ou simplesmente não foi implementado.</p><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Julgar se deve esperar z.ai: quais são &quot;implementados&quot;, quais são &quot;documentados explicitamente como não feitos&quot;</li><li>Entender claramente quais endpoints z.ai afeta (e quais endpoints não são afetados absolutamente)</li><li>Ver evidência de código-fonte/documento para cada conclusão (com links de número de linha do GitHub), conveniente para você próprio revisar</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><p>Você pode ter aberto o z.ai nas Antigravity Tools, mas ao usar encontrou esses confusões:</p><ul><li>Por que algumas solicitações vão para z.ai, outras não vão absolutamente?</li><li>O endpoint MCP pode ser tratado como &quot;Servidor MCP completo&quot;?</li><li>Interruptores que você vê na UI, realmente correspondem a implementação real?</li></ul><h2 id="o-que-e-integracao-z-ai-neste-projeto" tabindex="-1">O que é integração z.ai (neste projeto)? <a class="header-anchor" href="#o-que-e-integracao-z-ai-neste-projeto" aria-label="Permalink to &quot;O que é integração z.ai (neste projeto)?&quot;">​</a></h2><p><strong>Integração z.ai</strong> nas Antigravity Tools é um &quot;provedor upstream + extensão MCP&quot; opcional. Só em condições específicas intercepta solicitações de protocolo Claude, e fornece proxy de MCP Search/Reader e um servidor Vision MCP integrado mínimo; não é uma solução de substituição completa de todos os protocolos/capacidades.</p><div class="info custom-block"><p class="custom-block-title">Lembre-se de uma frase</p><p>Você pode tratar z.ai como &quot;provedor upstream opcional para solicitações Claude + um conjunto de endpoints MCP com interruptores&quot;, não trate como &quot;trazer todas as capacidades do z.ai completamente&quot;.</p></div><h2 id="implementado-estavel-e-disponivel-baseado-em-codigo-fonte" tabindex="-1">Implementado: estável e disponível (baseado em código-fonte) <a class="header-anchor" href="#implementado-estavel-e-disponivel-baseado-em-codigo-fonte" aria-label="Permalink to &quot;Implementado: estável e disponível (baseado em código-fonte)&quot;">​</a></h2><h3 id="_1-apenas-protocolo-claude-vai-para-z-ai-v1-messages-v1-messages-count-tokens" tabindex="-1">1) Apenas protocolo Claude vai para z.ai (/v1/messages + /v1/messages/count_tokens) <a class="header-anchor" href="#_1-apenas-protocolo-claude-vai-para-z-ai-v1-messages-v1-messages-count-tokens" aria-label="Permalink to &quot;1) Apenas protocolo Claude vai para z.ai (/v1/messages + /v1/messages/count_tokens)&quot;">​</a></h3><p>Encaminhamento upstream Anthropic do z.ai só acontece no ramo z.ai do handler Claude:</p><ul><li><code>POST /v1/messages</code>: quando <code>use_zai=true</code> chama <code>forward_anthropic_json(...)</code> para encaminhar solicitação JSON para endpoint compatível Anthropic do z.ai</li><li><code>POST /v1/messages/count_tokens</code>: quando z.ai ativado também encaminha; caso contrário retorna placeholder <code>{input_tokens:0, output_tokens:0}</code></li></ul><p>Evidência:</p><ul><li>Seleção de ramo z.ai e entrada de encaminhamento: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Ramo z.ai de count_tokens e retorno de placeholder: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Implementação de encaminhamento Anthropic upstream do z.ai: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><div class="tip custom-block"><p class="custom-block-title">Como entender &quot;resposta em streaming&quot;?</p><p><code>forward_anthropic_json</code> transmitirá corpo de resposta do upstream de volta ao cliente via <code>bytes_stream()</code>, não analisa SSE (ver construção de corpo de Response em <code>providers/zai_anthropic.rs</code>).</p></div><h3 id="_2-significado-real-do-modo-de-escalonamento-dispatch-mode" tabindex="-1">2) &quot;Significado real&quot; do modo de escalonamento (dispatch_mode) <a class="header-anchor" href="#_2-significado-real-do-modo-de-escalonamento-dispatch-mode" aria-label="Permalink to &quot;2) &quot;Significado real&quot; do modo de escalonamento (dispatch_mode)&quot;">​</a></h3><p><code>dispatch_mode</code> decide se <code>/v1/messages</code> vai para z.ai:</p><table tabindex="0"><thead><tr><th>dispatch_mode</th><th>O que acontece</th><th>Evidência</th></tr></thead><tbody><tr><td><code>off</code></td><td>Nunca usar z.ai</td><td><code>src-tauri/src/proxy/config.rs#L20-L37</code> + <code>src-tauri/src/proxy/handlers/claude.rs#L282-L314</code></td></tr><tr><td><code>exclusive</code></td><td>Todas as solicitações Claude vão para z.ai</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L285-L314</code></td></tr><tr><td><code>fallback</code></td><td>Só vai para z.ai quando pool Google indisponível (0 contas ou &quot;nenhuma conta disponível&quot;)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L288-L305</code></td></tr><tr><td><code>pooled</code></td><td>Trata z.ai como &quot;1 slot extra&quot; participando de polling (não garante necessariamente acerto)</td><td><code>src-tauri/src/proxy/handlers/claude.rs#L306-L312</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Mal-entendido comum de pooled</p><p><code>pooled</code> não é &quot;z.ai + pool de contas Google ambos usados, e distribuição estável por peso&quot;. No código escreveu explicitamente &quot;no strict guarantees&quot;, essencialmente é um slot de polling (só vai para z.ai quando <code>slot == 0</code>).</p></div><h3 id="_3-mapeamento-de-modelo-como-nomes-de-modelo-claude-se-tornam-glm-do-z-ai" tabindex="-1">3) Mapeamento de modelo: como nomes de modelo Claude se tornam glm-* do z.ai? <a class="header-anchor" href="#_3-mapeamento-de-modelo-como-nomes-de-modelo-claude-se-tornam-glm-do-z-ai" aria-label="Permalink to &quot;3) Mapeamento de modelo: como nomes de modelo Claude se tornam glm-* do z.ai?&quot;">​</a></h3><p>Antes de encaminhar para z.ai, se o corpo da solicitação tiver campo <code>model</code>, será reescrito:</p><ol><li>Correspondência exata de <code>proxy.zai.model_mapping</code> (simultaneamente suporta string original e chave lower-case)</li><li>Prefixo <code>zai:&lt;model&gt;</code>: remove <code>zai:</code> diretamente e usa</li><li><code>glm-*</code>: mantém inalterado</li><li>Não <code>claude-*</code>: mantém inalterado</li><li><code>claude-*</code> e contém <code>opus/haiku</code>: mapeia para <code>proxy.zai.models.opus/haiku</code>; caso contrário padrão <code>sonnet</code></li></ol><p>Evidência: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L149-L152" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></p><h3 id="_4-estrategia-de-seguranca-de-header-ao-encaminhar-evitando-vazar-chave-de-proxy-local" tabindex="-1">4) Estratégia de segurança de Header ao encaminhar (evitando vazar chave de proxy local) <a class="header-anchor" href="#_4-estrategia-de-seguranca-de-header-ao-encaminhar-evitando-vazar-chave-de-proxy-local" aria-label="Permalink to &quot;4) Estratégia de segurança de Header ao encaminhar (evitando vazar chave de proxy local)&quot;">​</a></h3><p>Encaminhamento upstream z.ai não &quot;traz todos os Headers como estão&quot;, mas fez duas camadas de defesa:</p><ul><li>Só libera pequena parte de Headers (por exemplo <code>content-type</code>, <code>accept</code>, <code>anthropic-version</code>, <code>user-agent</code>)</li><li>Injeta chave de API do z.ai no upstream (prioriza manter método de autenticação usado pelo cliente: <code>x-api-key</code> ou <code>Authorization: Bearer ...</code>)</li></ul><p>Evidência:</p><ul><li>Lista branca de Header: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L89" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li><li>Injetar auth z.ai: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L91-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></li></ul><h2 id="implementado-mcp-proxy-search-reader-vision-integrado" tabindex="-1">Implementado: MCP (proxy Search/Reader + Vision integrado) <a class="header-anchor" href="#implementado-mcp-proxy-search-reader-vision-integrado" aria-label="Permalink to &quot;Implementado: MCP (proxy Search/Reader + Vision integrado)&quot;">​</a></h2><h3 id="_1-mcp-search-reader-proxy-reverso-para-endpoint-mcp-do-z-ai" tabindex="-1">1) MCP Search/Reader: proxy reverso para endpoint MCP do z.ai <a class="header-anchor" href="#_1-mcp-search-reader-proxy-reverso-para-endpoint-mcp-do-z-ai" aria-label="Permalink to &quot;1) MCP Search/Reader: proxy reverso para endpoint MCP do z.ai&quot;">​</a></h3><p>Endpoint local e endereço upstream são codificados:</p><table tabindex="0"><thead><tr><th>Endpoint local</th><th>Endereço upstream</th><th>Interruptor</th><th>Evidência</th></tr></thead><tbody><tr><td><code>/mcp/web_search_prime/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_search_prime/mcp</code></td><td><code>proxy.zai.mcp.web_search_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L115-L135</code></td></tr><tr><td><code>/mcp/web_reader/mcp</code></td><td><code>https://api.z.ai/api/mcp/web_reader/mcp</code></td><td><code>proxy.zai.mcp.web_reader_enabled</code></td><td><code>src-tauri/src/proxy/handlers/mcp.rs#L137-L157</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">404 não é &quot;problema de rede&quot;</p><p>Enquanto <code>proxy.zai.mcp.enabled=false</code>, ou correspondente <code>web_search_enabled/web_reader_enabled=false</code>, estes endpoints retornarão diretamente 404.</p></div><p>Evidência:</p><ul><li>Interruptor total de MCP e verificação de chave z.ai: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L52-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Registro de rota: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L157-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></li></ul><h3 id="_2-vision-mcp-servidor-integrado-minimo-streamable-http-mcp" tabindex="-1">2) Vision MCP: servidor integrado mínimo &quot;Streamable HTTP MCP&quot; <a class="header-anchor" href="#_2-vision-mcp-servidor-integrado-minimo-streamable-http-mcp" aria-label="Permalink to &quot;2) Vision MCP: servidor integrado mínimo &quot;Streamable HTTP MCP&quot;&quot;">​</a></h3><p>Vision MCP não é proxy, é implementação integrada local:</p><ul><li>Endpoint: <code>/mcp/zai-mcp-server/mcp</code></li><li><code>POST</code> suporta: <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code></li><li><code>GET</code> retorna SSE keepalive (requer sessão já inicializada)</li><li><code>DELETE</code> termina sessão</li></ul><p>Evidência:</p><ul><li>Entrada principal de handler e despacho de método: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L376-L397" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Implementação de <code>initialize</code>, <code>tools/list</code>, <code>tools/call</code>: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L229-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></li><li>Posicionamento de &quot;implementação mínima&quot; do Vision MCP: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></li></ul><h3 id="_3-conjunto-de-ferramentas-do-vision-mcp-8-e-limites-de-tamanho-de-arquivo" tabindex="-1">3) Conjunto de ferramentas do Vision MCP (8) e limites de tamanho de arquivo <a class="header-anchor" href="#_3-conjunto-de-ferramentas-do-vision-mcp-8-e-limites-de-tamanho-de-arquivo" aria-label="Permalink to &quot;3) Conjunto de ferramentas do Vision MCP (8) e limites de tamanho de arquivo&quot;">​</a></h3><p>Lista de ferramentas vem de <code>tool_specs()</code>:</p><ul><li><code>ui_to_artifact</code></li><li><code>extract_text_from_screenshot</code></li><li><code>diagnose_error_screenshot</code></li><li><code>understand_technical_diagram</code></li><li><code>analyze_data_visualization</code></li><li><code>ui_diff_check</code></li><li><code>analyze_image</code></li><li><code>analyze_video</code></li></ul><p>Evidência: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L166-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L45-L53" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></p><p>Arquivos locais serão lidos e codificados em <code>data:&lt;mime&gt;;base64,...</code>, com limites rígidos simultaneamente:</p><ul><li>Limite de imagem 5 MB (<code>image_source_to_content(..., 5)</code>)</li><li>Limite de vídeo 8 MB (<code>video_source_to_content(..., 8)</code>)</li></ul><p>Evidência: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L111" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></p><h2 id="explicitamente-nao-implementado-nao-espere-baseado-em-declaracao-de-documento-e-detalhes-de-implementacao" tabindex="-1">Explicitamente não implementado / não espere (baseado em declaração de documento e detalhes de implementação) <a class="header-anchor" href="#explicitamente-nao-implementado-nao-espere-baseado-em-declaracao-de-documento-e-detalhes-de-implementacao" aria-label="Permalink to &quot;Explicitamente não implementado / não espere (baseado em declaração de documento e detalhes de implementação)&quot;">​</a></h2><h3 id="_1-monitoramento-de-uso-orcamento-z-ai-usage-budget-nao-implementado" tabindex="-1">1) Monitoramento de uso/orçamento z.ai (usage/budget) não implementado <a class="header-anchor" href="#_1-monitoramento-de-uso-orcamento-z-ai-usage-budget-nao-implementado" aria-label="Permalink to &quot;1) Monitoramento de uso/orçamento z.ai (usage/budget) não implementado&quot;">​</a></h3><p><code>docs/zai/implementation.md</code> escreveu explicitamente &quot;not implemented yet&quot;. Isso significa:</p><ul><li>Você não pode esperar que as Antigravity Tools forneçam consulta/alerta de uso/orçamento do z.ai</li><li>Governança de cota (Quota Protection) também não lerá automaticamente dados de orçamento/uso do z.ai</li></ul><p>Evidência: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_2-vision-mcp-nao-e-servidor-mcp-completo" tabindex="-1">2) Vision MCP não é Servidor MCP completo <a class="header-anchor" href="#_2-vision-mcp-nao-e-servidor-mcp-completo" aria-label="Permalink to &quot;2) Vision MCP não é Servidor MCP completo&quot;">​</a></h3><p>O Vision MCP atualmente é posicionado como &quot;implementação mínima suficiente para chamada de ferramenta&quot;: prompts/resources, resumibilidade, saída de ferramenta em streaming etc. ainda não feitos.</p><p>Evidência: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L34-L36" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></p><h3 id="_3-v1-models-claude-nao-refletira-lista-real-de-modelos-do-z-ai" tabindex="-1">3) <code>/v1/models/claude</code> não refletirá lista real de modelos do z.ai <a class="header-anchor" href="#_3-v1-models-claude-nao-refletira-lista-real-de-modelos-do-z-ai" aria-label="Permalink to &quot;3) `/v1/models/claude` não refletirá lista real de modelos do z.ai&quot;">​</a></h3><p>Este endpoint retorna lista de modelos do mapeamento integrado e mapeamento personalizado (<code>get_all_dynamic_models</code>), não vai solicitar <code>/v1/models</code> do upstream z.ai.</p><p>Evidência:</p><ul><li>Handler: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1162-L1183" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></li><li>Lógica de geração de lista: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></li></ul><h2 id="consulta-rapida-de-campos-de-configuracao-relacionados-a-z-ai" tabindex="-1">Consulta rápida de campos de configuração (relacionados a z.ai) <a class="header-anchor" href="#consulta-rapida-de-campos-de-configuracao-relacionados-a-z-ai" aria-label="Permalink to &quot;Consulta rápida de campos de configuração (relacionados a z.ai)&quot;">​</a></h2><p>Configuração z.ai está em <code>ProxyConfig.zai</code>, contendo estes campos:</p><ul><li><code>enabled</code> / <code>base_url</code> / <code>api_key</code></li><li><code>dispatch_mode</code> (<code>off/exclusive/pooled/fallback</code>)</li><li><code>model_mapping</code> (correspondência exata de substituição)</li><li><code>models.{opus,sonnet,haiku}</code> (mapeamento padrão de família Claude)</li><li><code>mcp.{enabled,web_search_enabled,web_reader_enabled,vision_enabled}</code></li></ul><p>Valores padrão (base_url / modelos padrão) também estão no mesmo arquivo:</p><ul><li><code>base_url = &quot;https://api.z.ai/api/anthropic&quot;</code></li><li><code>opus/sonnet = &quot;glm-4.7&quot;</code></li><li><code>haiku = &quot;glm-4.5-air&quot;</code></li></ul><p>Evidência: <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a>, <a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></p><hr><h2 id="resumo-desta-secao" tabindex="-1">Resumo desta seção <a class="header-anchor" href="#resumo-desta-secao" aria-label="Permalink to &quot;Resumo desta seção&quot;">​</a></h2><ul><li>z.ai atualmente só intercepta protocolo Claude (<code>/v1/messages</code> + <code>count_tokens</code>), outros endpoints de protocolo não são &quot;automaticamente ir para z.ai&quot;</li><li>MCP Search/Reader é proxy; Vision MCP é implementação mínima integrada, não Servidor MCP completo</li><li>Lista de modelos de <code>/v1/models/claude</code> vem de mapeamento local, não representa modelos reais do upstream</li></ul><hr><h2 id="proxima-secao" tabindex="-1">Próxima seção <a class="header-anchor" href="#proxima-secao" aria-label="Permalink to &quot;Próxima seção&quot;">​</a></h2><blockquote><p>Na próxima seção, aprenderemos <strong><a href="./../../changelog/release-notes/">Versões</a></strong>.</p></blockquote><hr><h2 id="apendice-referencias-de-codigo-fonte" tabindex="-1">Apêndice: Referências de código-fonte <a class="header-anchor" href="#apendice-referencias-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referências de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localizações do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>Escopo de integração z.ai (protocolo Claude + MCP + Vision MCP)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L12-L17" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>12-17</td></tr><tr><td>Modo de escalonamento z.ai e valores padrão de modelo</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L20-L116" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>20-116</td></tr><tr><td>base_url z.ai padrão / modelo padrão</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L265-L279" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>265-279</td></tr><tr><td>Lógica de seleção se <code>/v1/messages</code> vai para z.ai</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L256-L374" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>256-374</td></tr><tr><td>Encaminhamento z.ai de <code>/v1/messages/count_tokens</code> e retorno de placeholder</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/claude.rs#L1186-L1209" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/claude.rs</code></a></td><td>1186-1209</td></tr><tr><td>Encaminhamento upstream Anthropic do z.ai (encaminhamento JSON + retorno em streaming de resposta)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L133-L219" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>133-219</td></tr><tr><td>Regras de mapeamento de modelo z.ai (map_model_for_zai)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L13-L37" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>13-37</td></tr><tr><td>Lista branca de Header + injetar auth z.ai</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/providers/zai_anthropic.rs#L70-L110" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/providers/zai_anthropic.rs</code></a></td><td>70-110</td></tr><tr><td>Proxy MCP Search/Reader e interruptores</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/mcp.rs#L45-L157" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/mcp.rs</code></a></td><td>45-157</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Posicionamento de implementação mínima do Vision MCP (não Servidor MCP completo)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/vision-mcp.md#L17-L37" target="_blank" rel="noreferrer"><code>docs/zai/vision-mcp.md</code></a></td><td>17-37</td></tr><tr><td>Lista de ferramentas Vision e limites (tool_specs + tamanho de arquivo + stream=false)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/zai_vision_tools.rs#L57-L270" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/zai_vision_tools.rs</code></a></td><td>57-270</td></tr><tr><td>Origem de lista de modelos <code>/v1/models/claude</code> (mapeamento local, não consulta upstream)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L84-L132" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>84-132</td></tr><tr><td>Monitoramento de uso/orçamento não implementado (declaração de documento)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/zai/implementation.md#L194-L198" target="_blank" rel="noreferrer"><code>docs/zai/implementation.md</code></a></td><td>194-198</td></tr></tbody></table></details>',76)])])}const h=a(i,[["render",d]]);export{u as __pageData,h as default};
